// // Intentionally corrupting the ciphertext or tag will lead to decryption failure.
// console.log('\n--- Tampering Attempt ---');
// const tamperedEncryptedOutput = encryptedOutput.slice(0, -2) + 'ff'; // Corrupting the tag
// console.log('Tampered Output:', tamperedEncryptedOutput);
// try {
//     const decryptedTampered = decryptSecure(tamperedEncryptedOutput);
//     console.log('Decrypted Tampered (should not happen):', decryptedTampered);
// } catch (e) {
//     console.error('Successfully caught tampering:', e.message);
// }
```
